    bool FileExists(const std::string& path)
    {
        DWORD attributes = GetFileAttributesA(path.c_str());
        return attributes != INVALID_FILE_ATTRIBUTES && !(attributes & FILE_ATTRIBUTE_DIRECTORY);
    }

    std::string GetModuleDirectory()
    {
        char modulePath[MAX_PATH] = {0};
        HMODULE moduleHandle = NULL;

        if (GetModuleHandleExA(
                GET_MODULE_HANDLE_EX_FLAG_FROM_ADDRESS | GET_MODULE_HANDLE_EX_FLAG_UNCHANGED_REFCOUNT,
                reinterpret_cast<LPCSTR>(&GetModuleDirectory),
                &moduleHandle) == 0)
        {
            return std::string();
        }

        DWORD pathLength = GetModuleFileNameA(moduleHandle, modulePath, MAX_PATH);
        if (pathLength == 0 || pathLength == MAX_PATH)
        {
            return std::string();
        }

        std::string fullPath(modulePath, pathLength);
        std::size_t separatorPos = fullPath.find_last_of("\\/");
        if (separatorPos == std::string::npos)
        {
            return std::string();
        }

        return fullPath.substr(0, separatorPos);
    }

    std::string GetProjectDirectoryFromModuleDirectory(const std::string& moduleDirectory)
    {
        std::size_t lastSeparator = moduleDirectory.find_last_of("\\/");
        if (lastSeparator == std::string::npos)
        {
            return std::string();
        }

        std::string parentDirectory = moduleDirectory.substr(0, lastSeparator);
        lastSeparator = parentDirectory.find_last_of("\\/");
        if (lastSeparator == std::string::npos)
        {
            return std::string();
        }

        return parentDirectory.substr(0, lastSeparator);
    }

    bool IsSamePoint(const NXOpen::Point3d& first, const NXOpen::Point3d& second)
    {
        const double dx = first.X - second.X;
        const double dy = first.Y - second.Y;
        const double dz = first.Z - second.Z;
        return (dx * dx + dy * dy + dz * dz) <= (kPointTolerance * kPointTolerance);
    }

    NXOpen::Point3d MakeVector(const NXOpen::Point3d& fromPoint, const NXOpen::Point3d& toPoint)
    {
        NXOpen::Point3d vector;
        vector.X = toPoint.X - fromPoint.X;
        vector.Y = toPoint.Y - fromPoint.Y;
        vector.Z = toPoint.Z - fromPoint.Z;
        return vector;
    }

    double VectorLength(const NXOpen::Point3d& vector)
    {
        return std::sqrt(vector.X * vector.X + vector.Y * vector.Y + vector.Z * vector.Z);
    }

    double DistanceBetweenPoints(const NXOpen::Point3d& first, const NXOpen::Point3d& second)
    {
        return VectorLength(MakeVector(first, second));
    }

    double ComputeAngleInDegrees(const NXOpen::Point3d& vector1, const NXOpen::Point3d& vector2)
    {
        const double length1 = VectorLength(vector1);
        const double length2 = VectorLength(vector2);
        if (length1 <= 1.0e-9 || length2 <= 1.0e-9)
        {
            return 0.0;
        }

        double cosValue =
            (vector1.X * vector2.X + vector1.Y * vector2.Y + vector1.Z * vector2.Z) / (length1 * length2);

        if (cosValue > 1.0)
        {
            cosValue = 1.0;
        }
        else if (cosValue < -1.0)
        {
            cosValue = -1.0;
        }

        return std::acos(cosValue) * 180.0 / 3.14159265358979323846;
    }

    double ComputeThicknessFromCornerDistance(double cornerDistance, double angleInDegrees)
    {
        const double halfAngleInRadians = (angleInDegrees * 0.5) * 3.14159265358979323846 / 180.0;
        const double sineValue = std::sin(halfAngleInRadians);
        if (std::fabs(sineValue) <= 1.0e-9)
        {
            return 0.0;
        }

        return cornerDistance * sineValue;
    }

    bool IsRightAngle(double angleInDegrees, double toleranceInDegrees = 1.0)
    {
        return std::fabs(angleInDegrees - 90.0) <= toleranceInDegrees;
    }

    bool IsNearlyEqual(double firstValue, double secondValue, double tolerance)
    {
        return std::fabs(firstValue - secondValue) <= tolerance;
    }

