BanJjinCaiBian::BanJjinCaiBian()
{
    try
    {
        // Initialize the NX Open C++ API environment
        BanJjinCaiBian::theSession = NXOpen::Session::GetSession();
        BanJjinCaiBian::theUI = UI::GetUI();
        lastProcessedTag = NULL_TAG;
        lastSelectionSignature.clear();
        lastEnumValue = -1;
        createdFeatureTags.clear();
        edgeFeatureTags.clear();
        recentPointTag1 = NULL_TAG;
        recentPointTag2 = NULL_TAG;
        recentPointCoord1 = NXOpen::Point3d(0.0, 0.0, 0.0);
        recentPointCoord2 = NXOpen::Point3d(0.0, 0.0, 0.0);
        cutGap = NULL;
        bendInnerR = NULL;
        const std::string moduleDirectory = GetModuleDirectory();
        std::string dlxPath = "BanJjinCaiBian.dlx";

        if (!moduleDirectory.empty())
        {
            const std::string projectDirectory = GetProjectDirectoryFromModuleDirectory(moduleDirectory);
            const std::string projectDlxPath = projectDirectory + "\\BanJjinCaiBian.dlx";
            const std::string moduleDlxPath = moduleDirectory + "\\BanJjinCaiBian.dlx";

            if (!projectDirectory.empty() && FileExists(projectDlxPath))
            {
                dlxPath = projectDlxPath;
            }
            else if (FileExists(moduleDlxPath))
            {
                dlxPath = moduleDlxPath;
            }
        }

        std::strncpy(theDlxFileName, dlxPath.c_str(), sizeof(theDlxFileName) - 1);
        theDlxFileName[sizeof(theDlxFileName) - 1] = '\0';
        theDialog = BanJjinCaiBian::theUI->CreateDialog(theDlxFileName);
        // Registration of callback functions
        theDialog->AddApplyHandler(make_callback(this, &BanJjinCaiBian::apply_cb));
        theDialog->AddOkHandler(make_callback(this, &BanJjinCaiBian::ok_cb));
        theDialog->AddUpdateHandler(make_callback(this, &BanJjinCaiBian::update_cb));
        theDialog->AddInitializeHandler(make_callback(this, &BanJjinCaiBian::initialize_cb));
        theDialog->AddDialogShownHandler(make_callback(this, &BanJjinCaiBian::dialogShown_cb));
    }
    catch(exception&)
    {
        //---- Enter your exception handling code here -----
        throw;
    }
}

