//------------------------------------------------------------------------------
//Callback Name: initialize_cb
//------------------------------------------------------------------------------
void BanJjinCaiBian::initialize_cb()
{
    try
    {
        group0 = dynamic_cast<NXOpen::BlockStyler::Group*>(theDialog->TopBlock()->FindBlock("group0"));
        enum0 = dynamic_cast<NXOpen::BlockStyler::Enumeration*>(theDialog->TopBlock()->FindBlock("enum0"));
        selection0 = dynamic_cast<NXOpen::BlockStyler::SelectObject*>(theDialog->TopBlock()->FindBlock("selection0"));
        cutGap = dynamic_cast<NXOpen::BlockStyler::DoubleBlock*>(theDialog->TopBlock()->FindBlock("cutGap"));
        bendInnerR = dynamic_cast<NXOpen::BlockStyler::DoubleBlock*>(theDialog->TopBlock()->FindBlock("bendInnerR"));

        std::vector<NXOpen::Selection::MaskTriple> selectionMaskArray;
        selectionMaskArray.emplace_back(UF_solid_type, 0, UF_UI_SEL_FEATURE_ANY_EDGE);

        NXOpen::BlockStyler::PropertyList *selectionProps = selection0->GetProperties();
        selectionProps->SetSelectionFilter(
            "SelectionFilter",
            NXOpen::Selection::SelectionActionClearAndEnableSpecific,
            selectionMaskArray);
        selectionProps->SetEnum("SelectMode", 1);
        selectionProps->SetLogical("AutomaticProgression", false);
        selectionProps->SetLogical("PointOverlay", false);
        delete selectionProps;
        selectionProps = NULL;

        if (enum0 != NULL)
        {
            NXOpen::BlockStyler::PropertyList* enumProps = enum0->GetProperties();
            enumProps->SetEnum("Value", 0);
            delete enumProps;
            enumProps = NULL;
        }
    }
    catch(exception& ex)
    {
        //---- Enter your exception handling code here -----
        BanJjinCaiBian::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
}

