//------------------------------------------------------------------------------
//Callback Name: apply_cb
//------------------------------------------------------------------------------
int BanJjinCaiBian::apply_cb()
{
    int errorCode = 0;
    try
    {
        NXOpen::Part *workPart = theSession->Parts()->Work();
        if (workPart == NULL)
        {
            throw NXOpen::NXException::Create(1, "No work part is available.");
        }

        std::vector<NXOpen::TaggedObject*> selectedObjects = selection0->GetSelectedObjects();
        NXOpen::BlockStyler::PropertyList* selectionProps = selection0->GetProperties();
        const NXOpen::Point3d selectionPickPoint = selectionProps->GetPoint("PickPoint");
        delete selectionProps;
        selectionProps = NULL;

        const double cutGapValue = ClampCutGap(GetDoubleBlockValue(cutGap, 0.2));
        const double bendInnerRValue = ClampBendInnerR(GetDoubleBlockValue(bendInnerR, 0.2));

        for (NXOpen::TaggedObject* selectedObject : selectedObjects)
        {
            NXOpen::Edge *selectedEdge = dynamic_cast<NXOpen::Edge*>(selectedObject);
            if (selectedEdge != NULL)
            {
                ProcessEdgeSelection(workPart, theSession, enum0, selectedEdge, &selectionPickPoint, cutGapValue, bendInnerRValue, &createdFeatureTags);
                continue;
            }
        }
    }
    catch(exception& ex)
    {
        //---- Enter your exception handling code here -----
        errorCode = 1;
        BanJjinCaiBian::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}

//------------------------------------------------------------------------------
//Callback Name: update_cb
//------------------------------------------------------------------------------
int BanJjinCaiBian::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
    try
    {
        if(block == selection0 || block == enum0 || block == cutGap || block == bendInnerR)
        {
            NXOpen::BlockStyler::PropertyList* selectionProps = selection0->GetProperties();
            std::vector<NXOpen::TaggedObject*> selectedObjects = selection0->GetSelectedObjects();
            const NXOpen::Point3d selectionPickPoint = selectionProps->GetPoint("PickPoint");
            delete selectionProps;
            selectionProps = NULL;
            std::vector<NXOpen::Edge*> selectedEdges;
            for (NXOpen::TaggedObject* selectedObject : selectedObjects)
            {
                NXOpen::Edge* selectedEdge = dynamic_cast<NXOpen::Edge*>(selectedObject);
                if (selectedEdge != NULL)
                {
                    selectedEdges.push_back(selectedEdge);
                }
            }

            const std::string currentSignature = BuildSelectionSignature(selectedObjects);
            int currentEnumValue = 0;
            if (enum0 != NULL)
            {
                NXOpen::BlockStyler::PropertyList* enumProps = enum0->GetProperties();
                currentEnumValue = enumProps->GetEnum("Value");
                delete enumProps;
                enumProps = NULL;
            }

            const double cutGapValue = ClampCutGap(GetDoubleBlockValue(cutGap, 0.2));
            const double bendInnerRValue = ClampBendInnerR(GetDoubleBlockValue(bendInnerR, 0.2));
            const bool settingsChanged = (block == cutGap || block == bendInnerR);
            const bool enumChanged = settingsChanged || currentEnumValue != lastEnumValue;
            if (!currentSignature.empty())
            {
                NXOpen::Part* workPart = theSession->Parts()->Work();
                if (workPart == NULL)
                {
                    return 0;
                }

                if (enumChanged)
                {
                    DeleteCreatedFeatures(&createdFeatureTags);
                    edgeFeatureTags.clear();
                }
                else
                {
                    std::set<tag_t> currentEdgeTags;
                    for (NXOpen::Edge* selectedEdge : selectedEdges)
                    {
                        if (selectedEdge != NULL)
                        {
                            currentEdgeTags.insert(selectedEdge->Tag());
                        }
                    }

                    for (auto it = edgeFeatureTags.begin(); it != edgeFeatureTags.end(); )
                    {
                        if (currentEdgeTags.find(it->first) == currentEdgeTags.end())
                        {
                            DeleteCreatedFeatures(&it->second);
                            it = edgeFeatureTags.erase(it);
                        }
                        else
                        {
                            ++it;
                        }
                    }
                }

                for (NXOpen::Edge* selectedEdge : selectedEdges)
                {
                    if (selectedEdge == NULL)
                    {
                        continue;
                    }

                    const tag_t edgeTag = selectedEdge->Tag();
                    if (!enumChanged && edgeFeatureTags.find(edgeTag) != edgeFeatureTags.end())
                    {
                        continue;
                    }

                    std::vector<tag_t> localCreatedFeatureTags;
                    ProcessEdgeSelection(
                        workPart,
                        theSession,
                        enum0,
                        selectedEdge,
                        &selectionPickPoint,
                        cutGapValue,
                        bendInnerRValue,
                        &localCreatedFeatureTags);
                    edgeFeatureTags[edgeTag] = localCreatedFeatureTags;
                }

                RefreshCreatedFeatureTags(edgeFeatureTags, &createdFeatureTags);
                lastSelectionSignature = currentSignature;
                lastEnumValue = currentEnumValue;
                lastProcessedTag = selectedObjects[0] != NULL ? selectedObjects[0]->Tag() : NULL_TAG;
            }
            else if (currentSignature.empty())
            {
                DeleteCreatedFeatures(&createdFeatureTags);
                edgeFeatureTags.clear();
                lastSelectionSignature.clear();
                lastEnumValue = currentEnumValue;
            }
        }
    }
    catch(exception& ex)
    {
        //---- Enter your exception handling code here -----
        BanJjinCaiBian::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return 0;
}

